using System;

class Program
{
    static bool IsPalindrome(string text)
    {
        string cleaned = text.ToLower().Replace(" ", "");
        int left = 0;
        int right = cleaned.Length - 1;

        while (left < right)
        {
            if (cleaned[left] != cleaned[right])
            {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }

    static bool IsNumberPalindrome(int number)
    {
        int original = number;
        int reversed = 0;

        while (number > 0)
        {
            reversed = reversed * 10 + (number % 10);
            number /= 10;
        }

        return original == reversed;
    }

    static void Main()
    {
        string[] words = { "kayak", "araba", "anna", "elma", "a man a plan a canal panama" };

        Console.WriteLine("Kelime testleri:");
        foreach (string word in words)
        {
            Console.WriteLine($"'{word}' palindrome mu: {IsPalindrome(word)}");
        }

        Console.WriteLine("\nSayi testleri:");
        int[] numbers = { 12321, 12345, 1001, 5 };
        foreach (int num in numbers)
        {
            Console.WriteLine($"{num} palindrome mu: {IsNumberPalindrome(num)}");
        }
    }
}
